"""
MKT Christ Commentary — Psalms chapters 9–17
Run: python3 scripts/zc-christ-psalms-9-17.py

Key Christological decisions in this range:
- Ps 9/10 acrostic pair: the divine Judge enthroned = Christ as Judge (John 5:22-27; Rev 20:11)
- Ps 10:1 'why do you stand far off' = cry of dereliction typology (Ps 22 parallel)
- Ps 11:4 heavenly temple/throne = Christ's heavenly session (Heb 8:1)
- Ps 11:7 'see his face' = beatific vision promised to the pure in heart (Matt 5:8)
- Ps 12:6 'words of the LORD are flawless' = Christ as the living Word (John 1:1)
- Ps 13 'how long' = desolation prayer fulfilled in Christ's Passion
- Ps 14:1-3 cited by Paul in Rom 3:10-12 to establish universal need for Christ's righteousness
- Ps 15 entrance liturgy = Christ as the only one who fully meets the standard; union-with-Christ entry
- Ps 16:10 'not abandon to Sheol / see decay' = cited by Peter (Acts 2:25-31) and Paul (Acts 13:35)
  as resurrection prophecy — the key Christological verse in this range
- Ps 17:15 'when I awake I will see your face' = resurrection hope; the 'awaking' as type of resurrection
- mkt-christ requires an entry for every verse including brief transitional ones
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "9": {
    "1": '<p>The vow to praise with the whole heart anticipates the perfect worshiper. Every human act of thanksgiving is shadowed by a heart that is divided — part devoted, part distracted. Christ alone gave thanks to the Father with a perfectly undivided heart (John 11:41-42; Matt 11:25-26; John 17:4). His praise was the first perfectly whole offering of human devotion, and his people are drawn into it through union with him (Eph 5:19-20; Col 3:17).</p>',
    "2": '<p>"I will be glad and rejoice in you; I will sing the praises of your name, O Most High" — the joy in YHWH that marks the redeemed heart. Jesus expressed this joy most fully in John 15:11: "I have told you this so that my joy may be in you and that your joy may be complete." The Messianic community inherits the joy of the anointed Son — his rejoicing in the Father becomes the pattern for theirs.</p>',
    "3": '<p>The enemies turning back and stumbling before YHWH anticipates the defeat of all opposition to Christ. At the empty tomb, the guards "trembled and became like dead men" (Matt 28:4). At the name of Jesus, every knee will bow and every tongue confess (Phil 2:10-11). The scattering of enemies — which the psalmist prays — is accomplished definitively at the resurrection.</p>',
    "4": '<p>"For you have upheld my right and my cause, sitting enthroned as the righteous judge" — Christ is the one whose cause was perfectly upheld by the Father in the resurrection. The raising of Jesus was the Father\'s verdict: the cross was injustice; the empty tomb is the divine acquittal of the righteous sufferer (Rom 4:25 — "he was raised for our justification"). The Father who sits as righteous judge vindicated his Son, and in his Son vindicates all who are united to him.</p>',
    "5": '<p>The blotting out of the names of the wicked from the divine record echoes the book-of-life theology (Rev 3:5; 20:15). Christ is both the Lamb in whose book the names of the redeemed are written (Rev 13:8; 21:27) and the judge before whom the books are opened (Rev 20:12). That he "blots out their name forever" points toward the final judgment where every claim to self-justification apart from Christ is permanently erased.</p>',
    "6": '<p>The complete ruin of the enemy — cities destroyed, memory blotted out — is the language of final judgment. The NT applies this eschatological pattern to the defeat of Satan and the powers (1 John 3:8; Heb 2:14; Rev 20:10). Christ\'s cross was the decisive blow against the enemy kingdom; the final judgment extends that defeat to its ultimate completion.</p>',
    "7": '<p>"But the LORD reigns forever; he has established his throne for judgment" — Christ the enthroned King-Judge. Jesus declared "All authority in heaven and on earth has been given to me" (Matt 28:18) after the resurrection. The Father committed all judgment to the Son (John 5:22: "the Father judges no one, but has entrusted all judgment to the Son"). The eternal throne of YHWH is the throne on which the risen Christ is seated (Rev 3:21; 22:1).</p>',
    "8": '<p>"He rules the world in righteousness and judges the peoples with equity" — Christ\'s judicial reign is characterized by perfect righteousness and equity. Acts 17:31: "God has set a day when he will judge the world with justice by the man he has appointed. He has given proof of this to everyone by raising him from the dead." The resurrection-as-credential for universal judgment: the world will be judged by the one who was himself judged unjustly and vindicated by God.</p>',
    "9": '<p>"The LORD is a refuge for the oppressed, a stronghold in times of trouble" — Christ as the ultimate refuge. Heb 6:18: "we who have fled to take hold of the hope set before us" — the imagery of fleeing to a city of refuge (Num 35) applied to taking hold of Christ. Jesus himself is the "city of refuge" — those who flee to him for sanctuary are safe from the avenger of blood, which is the law\'s condemnation (Rom 8:1: "no condemnation for those who are in Christ Jesus").</p>',
    "10": '<p>"Those who know your name trust in you, for you, LORD, have never forsaken those who seek you" — the promise of divine faithfulness to those who seek. Christ embodies this promise — he is the one through whom YHWH is known by name (John 17:6: "I have revealed you to those whom you gave me out of the world"; John 17:26: "I have made you known to them"). To know the Father\'s name through the Son is the foundation of unshakeable trust.</p>',
    "11": '<p>"Sing the praises of the LORD, enthroned in Zion; proclaim among the nations what he has done" — the missionary dimension of Messianic praise. The proclamation "among the nations" anticipates the Great Commission (Matt 28:19-20) and the Pentecost mission (Acts 2:5-11). Christ is "enthroned in Zion" — the heavenly Zion (Heb 12:22-24) from which the gospel goes out to all nations. The risen Lord\'s acts are the content of the proclamation.</p>',
    "12": '<p>"For he who avenges blood remembers; he does not ignore the cries of the afflicted" — Christ is the avenger of blood for his people (Rev 6:10-11 — the martyrs cry "how long?" and are told to wait until the full number is complete; Rev 19:2 — he has avenged the blood of his servants). The divine memory of every cry of the afflicted reaches its fullness in Christ who both suffered as the afflicted one and will avenge all the afflicted at his return.</p>',
    "13": '<p>"LORD, see how my enemies persecute me! Have mercy and lift me up from the gates of death" — the prayer for rescue from death\'s threshold. Christ himself descended to the uttermost depth — "the gates of death" (Matt 12:40; Acts 2:24 — "it was impossible for death to keep its hold on him"). The prayer for rescue from the gates of death was answered in the resurrection: the gate opened from the inside, and the one who prayed was lifted up to life.</p>',
    "14": '<p>"...that I may declare your praises in the gates of Daughter Zion, and there rejoice in your salvation" — Heb 2:12 quotes Ps 22:22: "I will declare your name to my brothers and sisters; in the assembly I will sing your praises" — the risen Christ praising the Father in the midst of the church. The movement of v. 14 anticipates this: the prayer to be lifted from death\'s gates leads directly to proclamation in Zion\'s gates. Rescue becomes testimony; testimony becomes communal praise.</p>',
    "15": '<p>"The nations have fallen into the pit they have dug; their feet are caught in the net they have hidden" — the self-destructive principle of sin, realized most fully at the cross. Those who plotted against Christ — Judas, the chief priests, Pilate — were each caught in their own nets: Judas by guilt and self-destruction; the chief priests by the fall of the temple they sought to protect (70 CE); Rome by its own imperial overreach. The cross that was intended to destroy Christ became the instrument of salvation; the stone the builders rejected became the cornerstone (Ps 118:22; Acts 4:11).</p>',
    "16": '<p>"The LORD is known by his acts of justice; the wicked are ensnared by the work of their hands" — the divine revelation through historical action climaxes in the cross and resurrection. God\'s justice — his righteous judgment of sin — was manifested at Golgotha (Rom 3:25-26: "God presented Christ as a sacrifice of atonement... to demonstrate his justice... so as to be just and the one who justifies those who have faith in Jesus"). The work of the wicked hands that crucified Christ became the very act of redemption.</p>',
    "17": '<p>"The wicked go down to the realm of the dead, all the nations that forget God" — the ultimate descent into death contrasts with Christ\'s descent-and-ascent. Christ went down to the realm of the dead (Acts 2:31; 1 Pet 3:19) not as one judged but as the conqueror who holds "the keys of death and Hades" (Rev 1:18). The nations that forget God face this descent without rescue; the nations that remember him through Christ face death as a passage, not a destination (1 Cor 15:54-57).</p>',
    "18": '<p>"But God will never forget the needy; the hope of the afflicted will never perish" — the beatitude theology of Christ. The Beatitudes (Matt 5:3-12) are the direct continuation of this promise: "blessed are the poor in spirit," "blessed are the meek," "blessed are those who hunger and thirst for righteousness." Christ announced himself as the fulfillment of this promise to the afflicted (Luke 4:18 — "the Spirit of the Lord is on me, because he has anointed me to proclaim good news to the poor"). The needy are never forgotten because the Son of God himself became needy (2 Cor 8:9).</p>',
    "19": '<p>"Arise, LORD, do not let mortals triumph; let the nations be judged in your presence" — the prayer for divine intervention answered definitively in the resurrection. "Arise (<em>qûmāh</em>)" is the prayer-equivalent of the Num 10:35 battle cry ("Rise up, LORD!") and the language of resurrection (<em>qûm</em> = to rise, stand up). The resurrection is God\'s definitive "arising" to judge the nations — the final demonstration that mortals do not have the final word (Acts 17:31).</p>',
    "20": '<p>"Strike them with terror, LORD; let the nations know they are only mortal" — the goal of divine judgment: that all human pride before God be ended. Paul echoes this in Rom 3:19-20: the purpose of the law is that "every mouth may be silenced and the whole world held accountable to God." Christ as judge accomplishes what the law declared: the finitude and fallibility of every human claim to self-sufficiency. Before the risen Christ, all mortal pretension collapses.</p>'
  },
  "10": {
    "1": '<p>"Why, LORD, do you stand far off? Why do you hide yourself in times of trouble?" — the cry of divine absence that reaches its culmination in Christ\'s cross. Ps 22:1 is the canonical expression: "My God, my God, why have you forsaken me?" — which Jesus cried in Matt 27:46 and Mark 15:34. Ps 10:1 belongs to the same family of desolation prayers. Christ inhabited the depth of this question — not merely citing it but living it, experiencing the actual absence of divine consolation so that the abandonment of sin could be fully borne and exhausted.</p>',
    "2": '<p>The wicked pursuing the poor in arrogance describes the spiritual dynamic that opposed Christ. His entire ministry was characterized by the powerful targeting the powerless — and targeting him for his alignment with them. The religious establishment pursued Jesus for associating with tax collectors and sinners (Luke 5:30), and ultimately pursued him to the cross (John 11:47-53). In being hunted by the arrogant, Christ identified himself with every oppressed person throughout history.</p>',
    "3": '<p>"The wicked man boasts about the cravings of his heart; he blesses the greedy and reviles the LORD" — the idolatry of self-exaltation. Paul\'s analysis in Rom 1:21-23 identifies this as the root human sin: "they neither glorified him as God nor gave thanks to him... their thinking became futile." Christ exposed this pattern most directly in his confrontations with the Pharisees (Matt 23) and in the parables of self-exaltation (Luke 18:9-14 — the Pharisee who prayed about his own virtues).</p>',
    "4": '<p>"In his pride the wicked man does not seek him; in all his thoughts there is no room for God" — the practical atheism of self-sufficiency. Jesus diagnosed this in the parable of the rich fool (Luke 12:16-21): the man whose plans had no room for God. The incarnation is God\'s response to a world with no room for him — he entered it anyway, born into a borrowed stable (Luke 2:7). The rejection of Christ is the definitive form of this verse: in the climactic moment of divine presence, there was "no room."</p>',
    "5": '<p>"His ways are always prosperous; your laws are rejected by him; he sneers at all his enemies" — the apparent prosperity of the wicked that deceives. Jesus addressed this in the parable of the rich man and Lazarus (Luke 16:19-31): visible prosperity and suffering are not reliable indicators of divine favor. The cross is the ultimate inversion: the one who appeared cursed (Gal 3:13 — "cursed is everyone who is hung on a pole") was in fact carrying the blessing of the world.</p>',
    "6": '<p>"He says to himself, \'Nothing will ever shake me.\' He swears, \'No one will ever do me harm\'" — the false security of self-confidence. Christ warned against this repeatedly: "But God said to him, \'You fool! This very night your life will be demanded from you\'" (Luke 12:20). The one who built on rock (Christ\'s words) would stand; the one who built on sand (self-sufficiency) would fall (Matt 7:24-27). The whole security of the believer is in Christ, not self.</p>',
    "7": '<p>"His mouth is full of lies and threats; trouble and evil are under his tongue" — James 3:6-8 develops the theological significance of the corrupt tongue: "the tongue is a fire, a world of evil... it corrupts the whole body." Christ diagnosed the tongue\'s evil as a symptom of a corrupt heart (Matt 15:18: "the things that come out of a person\'s mouth come from the heart"). Paul quotes a cluster of passages including Ps 10:7 in Rom 3:14 as part of his diagnosis of universal human corruption requiring Christ\'s righteousness.</p>',
    "8": '<p>The wicked lying in wait to murder the innocent — this pattern culminated in the cross. Ps 10:8-10 pictures an ambush: hidden waiting, then sudden attack on the unsuspecting. The betrayal of Jesus by Judas (Matt 26:14-16, 47-50) and the night-time arrest in Gethsemane follow exactly this pattern — the chief priests and teachers waited for "an opportunity" (Luke 22:6), then struck in the night. Christ walked into the ambush knowingly, laying down his life rather than having it taken (John 10:18).</p>',
    "9": '<p>"He lies in wait like a lion in cover; he lies in wait to catch the helpless" — the lion-imagery for the enemy connects to 1 Pet 5:8 ("your enemy the devil prowls around like a roaring lion looking for someone to devour") and Rev 5:5 (Christ as "the Lion of the tribe of Judah" who has triumphed). The evil lion who hunts the helpless is overcome by the Lion who gave himself to be hunted, so that through his willing surrender he defeated the predator (Heb 2:14-15: "by his death he might break the power of him who holds the power of death").</p>',
    "10": '<p>"His victims are crushed, they collapse; they fall under his strength" — the condition of those crushed by sin and its consequences, which Christ specifically came to address. Luke 4:18 (Isa 61:1): "He has sent me to proclaim freedom for the prisoners and recovery of sight for the blind, to set the oppressed free." Christ\'s entire ministry was oriented toward those who had been crushed by the enemy — the demon-possessed, the disease-ridden, the social outcasts, the spiritually broken.</p>',
    "11": '<p>"He says to himself, \'God will never notice; he covers his face and never sees\'" — the denial of divine omniscience that sin requires. Christ exposed this illusion consistently: "Nothing is hidden that will not be disclosed" (Luke 8:17); "your Father, who sees what is done in secret, will reward you" (Matt 6:4, 6, 18). The cross made visible what was hidden — it publicly displayed "the rulers and authorities" (Col 2:15) and their character, "triumphing over them by the cross." What sin tries to conceal, the cross unmasks.</p>',
    "12": '<p>"Arise, LORD! Lift up your hand, O God. Do not forget the helpless" — the resurrection prayer at the center of the psalm. As in Ps 9:19-20, the petition for divine arising reaches its answer in the resurrection of Christ. God "lifted up his hand" against sin and death in raising Christ from the dead (Eph 1:19-20: "the incomparably great power... which he exerted when he raised Christ from the dead"). The helpless — those who cannot save themselves — are the primary beneficiaries of this arising.</p>',
    "13": '<p>"Why does the wicked man revile God? Why does he say to himself, \'He won\'t call me to account\'?" — the fundamental failure of accountability before God that the cross addresses. Christ\'s death was the definitive calling-to-account: all sin was held accountable at Calvary (2 Cor 5:21 — "God made him who had no sin to be sin for us"). The resurrection is the announcement that the account has been settled and the one who bore accountability for sin has been vindicated.</p>',
    "14": '<p>"But you, God, see the trouble of the afflicted; you consider their grief and take it in hand" — YHWH as the one who takes in hand the cause of the afflicted. The incarnation is the supreme taking-in-hand: "In all their distress he too was distressed... he lifted them up and carried them all the days of old" (Isa 63:9). Christ taking human suffering "in hand" — literally, physically, in his own body (Isa 53:4: "Surely he took up our pain and bore our suffering"; 1 Pet 2:24) — is the fulfillment of this verse.</p>',
    "15": '<p>"Break the arm of the wicked man; call the evildoer to account for his wickedness that would not otherwise be found out" — the prayer for the defeat of the enemy\'s power. Christ "broke the arm" of the wicked through the cross (1 John 3:8: "The reason the Son of God appeared was to destroy the devil\'s work"; Col 2:15: "having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross"). The enemy\'s power is broken; its complete accounting awaits the final judgment (Rev 20:10).</p>',
    "16": '<p>"The LORD is King forever and ever; the nations will perish from his land" — Christ\'s eternal kingship declared. Rev 11:15: "The kingdom of the world has become the kingdom of our Lord and of his Messiah, and he will reign for ever and ever." The nations that opposed Christ\'s kingdom will be purged from the renewed creation — not through ethnic exclusion but through the exclusion of rebellion itself. The new earth will have no room for the opposition described in Ps 10:1-15.</p>',
    "17": '<p>"You, LORD, hear the desire of the afflicted; you encourage them, and you listen to their cry" — Christ\'s ministry precisely exemplified this divine listening. He stopped for blind Bartimaeus when the crowd tried to silence him (Mark 10:46-52). He stopped for the hemorrhaging woman who touched his garment in a crowd (Mark 5:25-34). He heard the one leper who returned to give thanks (Luke 17:11-19). The Son\'s attentiveness to the afflicted was the visible, embodied form of this verse.</p>',
    "18": '<p>"...defending the fatherless and the oppressed, so that mere earthly mortals will never again strike terror" — the eschatological promise: the protection of the vulnerable, and the end of terror from human oppressors. This finds its fulfillment in the new creation (Rev 21:4: "there will be no more death or mourning or crying or pain") and its first-fruits in Christ\'s kingdom where the excluded are welcomed (Matt 19:14 — "let the children come to me"; Gal 3:28 — "there is neither slave nor free, neither male nor female, for you are all one in Christ Jesus").</p>'
  },
  "11": {
    "1": '<p>"In the LORD I take refuge. How then can you say to me: \'Flee like a bird to your mountain\'?" — Christ as the refuge that makes flight unnecessary. Heb 6:18: those who have "fled to take hold of the hope set before us" — the imagery of fleeing to a city of refuge applied to the safety found in Christ. When crisis comes, the temptation is flight; Christ\'s answer to his disciples before Gethsemane (John 14:27 — "Do not let your hearts be troubled and do not be afraid") is the same confidence as this verse: the refuge is secure, flight unnecessary.</p>',
    "2": '<p>"For look, the wicked bend their bows; they set their arrows against the strings to shoot from the shadows at the upright in heart" — the hidden attacks of the enemy against Christ and his people. The shadow-attack typifies the Passion: the plotting in secret (Matt 26:3-4 — "the chief priests and elders... plotted to arrest Jesus secretly"), the betrayal by one of his own (John 13:21-30). The attack from shadows is the enemy\'s preferred mode — light, which Christ is (John 8:12), exposes and defeats it.</p>',
    "3": '<p>"When the foundations are being destroyed, what can the righteous do?" — the crisis of foundational collapse. Christ\'s answer: "Heaven and earth will pass away, but my words will never pass away" (Matt 24:35). When every visible foundation crumbles — temple, nation, social order — the words of Christ remain. The foundation that cannot be destroyed is not an institution but a person (1 Cor 3:11: "no one can lay any foundation other than the one already laid, which is Jesus Christ").</p>',
    "4": '<p>"The LORD is in his holy temple; the LORD is on his heavenly throne. He observes everyone on earth; his eyes examine them" — Christ\'s heavenly session after the ascension. Heb 8:1-2: "We do have such a high priest, who sat down at the right hand of the throne of the Majesty in heaven, and who serves in the sanctuary, the true tabernacle set up by the Lord." The risen Christ in the heavenly sanctuary sees and examines — his priestly observation is not surveillance but intercession (Heb 7:25: "he always lives to intercede for them").</p>',
    "5": '<p>"The LORD examines the righteous, but the wicked, those who love violence, he hates with a passion" — Christ\'s righteous examination of his people. Rev 2-3 (the letters to the seven churches) shows the risen Christ "examining" each congregation — seeing their works, commending their faithfulness, correcting their failures. The examination is not punitive but purifying: "I counsel you to buy from me gold refined in the fire, so you can become rich" (Rev 3:18). Christ examines because he loves and desires righteousness in his people.</p>',
    "6": '<p>"On the wicked he will rain fiery coals and burning sulfur; a scorching wind will be their lot" — the coming judgment of Christ. 2 Thess 1:7-9: "when the Lord Jesus is revealed from heaven in blazing fire with his powerful angels. He will punish those who do not know God... they will be punished with everlasting destruction." Rev 14:10: those who receive the mark of the beast "will drink the wine of God\'s fury... they will be tormented with burning sulfur." The fiery judgment of Ps 11:6 is the eschatological reality to which Christ will return.</p>',
    "7": '<p>"For the LORD is righteous, he loves justice; the upright will see his face" — Christ as both the one who loves justice and the one through whom the upright see the divine face. Matt 5:8: "Blessed are the pure in heart, for they will see God." Rev 22:4: "They will see his face, and his name will be on their foreheads." The vision of God\'s face — unmediated divine presence — was the supreme covenant aspiration (Exod 33:18-23, where Moses could not see the face and live). Christ is both the one whose face is seen and the one who makes the seeing possible by purifying the heart (1 John 3:2: "when Christ appears, we shall be like him, for we shall see him as he is").</p>'
  },
  "12": {
    "1": '<p>"Help, LORD, for no one is faithful anymore; those who are loyal have vanished from the human race" — the condition of universal unfaithfulness that makes the incarnation necessary. Rom 3:10-12 (drawing on Ps 14) reaches the same conclusion: "There is no one righteous, not even one... there is no one who does good." The psalmist\'s lament over the disappearance of faithful people sets the stage for the one Faithful Person whose faithfulness covers the unfaithfulness of all: Christ, "the faithful and true witness" (Rev 3:14), "faithful to the one who appointed him" (Heb 3:2).</p>',
    "2": '<p>"Everyone lies to their neighbor; they flatter with their lips but harbor deception in their hearts" — Christ as the truth who exposed and overcame universal deception. John 1:14: "the Word became flesh and made his dwelling among us... full of grace and truth." John 8:32: "the truth will set you free." Christ confronted the deception of his generation most directly in Matt 23 (the woes against hypocrites whose lips honored God but whose hearts were far from him — quoting Isa 29:13). He is the antithesis of this verse: no flattery, only truth.</p>',
    "3": '<p>"May the LORD silence all flattering lips and every boastful tongue" — the prayer for the end of self-serving speech. The New Creation will be a place where all false speech is ended: "Nothing impure will ever enter it, nor will anyone who does what is shameful or deceitful, but only those whose names are written in the Lamb\'s book of life" (Rev 21:27). Christ\'s judgment includes the judgment of words (Matt 12:36: "everyone will have to give account on the day of judgment for every empty word they have spoken").</p>',
    "4": '<p>"Those who say, \'By our tongues we will prevail; our own lips will defend us — who is lord over us?\'" — the arrogance of autonomous speech that refuses accountability. Christ answered this claim simply: "there is a judge for the one who rejects me and does not accept my words; the very words I have spoken will condemn them at the last day" (John 12:48). The one who says "who is lord over us?" will discover the answer at the judgment seat of Christ (2 Cor 5:10).</p>',
    "5": '<p>"\'Because the poor are plundered and the needy groan, I will now arise,\' says the LORD" — the divine arising in response to the cry of the poor. The incarnation is God\'s supreme "arising" in response to human groaning — the condescension of the eternal Son into human poverty and suffering (2 Cor 8:9: "though he was rich, yet for your sake he became poor"). Christ is both the one who arises to defend and the one who became poor in order to make the poor rich.</p>',
    "6": '<p>"And the words of the LORD are flawless, like silver purified in a crucible, like gold refined seven times" — Christ as the living Word perfectly purified. John 1:1: "In the beginning was the Word, and the Word was with God, and the Word was God." Unlike human speech (vv. 2-4) which is full of flattery and deception, the divine Word is without any admixture of falsehood. The seven-times-refined purity points to perfection — and Christ\'s words were confirmed perfect by the testing of Satan\'s temptation (Matt 4:1-11; Heb 4:15), the cross, and the resurrection.</p>',
    "7": '<p>"You, LORD, will keep the needy safe and will protect us forever from this generation" — Christ\'s promise to his own: "I give them eternal life, and they shall never perish; no one will snatch them out of my hand" (John 10:28-29). The protection is absolute and permanent — "forever from this generation" anticipates the eschatological security of those who are in Christ (Rom 8:35-39: nothing can separate us from the love of God in Christ Jesus).</p>',
    "8": '<p>"The wicked freely strut about when what is vile is honored among men" — the cultural inversion that exalts what God calls evil. Christ addressed this specifically: "What people value highly is detestable in God\'s sight" (Luke 16:15). The church is called not to conform to the pattern of this world (Rom 12:2) — the strutting of the wicked does not set the standard. Christ, who was despised and rejected (Isa 53:3), defines honor by the Father\'s perspective, not the crowd\'s.</p>'
  },
  "13": {
    "1": '<p>"How long, LORD? Will you forget me forever? How long will you hide your face from me?" — the "how long" question is the lament genre\'s most honest expression of faith under desolation. Christ entered this question at its deepest point: "My God, my God, why have you forsaken me?" (Matt 27:46, citing Ps 22:1). The "how long?" of human suffering and divine hiddenness is real — Christ did not deny it or resolve it cheaply. He descended into it, making it his own, so that no one who prays this prayer prays it alone.</p>',
    "2": '<p>"How long must I wrestle with my thoughts and day after day have sorrow in my heart? How long will my enemy triumph over me?" — the interior suffering that accompanied Christ in Gethsemane: "My soul is overwhelmed with sorrow to the point of death" (Matt 26:38; Mark 14:34). The sorrow in the heart, the inner wrestling, the apparent triumph of the enemy — these were Christ\'s experience in the Garden and at Golgotha. He prayed "may this cup be taken from me" — the authentic prayer of one who knew the full weight of what was coming.</p>',
    "3": '<p>"Look on me and answer, LORD my God. Give light to my eyes, or I will sleep in death" — the prayer for life answered by resurrection. "Give light to my eyes" — the dimming of the eyes was the physical sign of approaching death; the giving of light is the reversal of death. Christ slept in death for three days (Matt 12:40: "three days and three nights in the heart of the earth") and woke to resurrection light. For believers united to him, the sleep of death is not final: "Our friend Lazarus has fallen asleep; but I am going there to wake him up" (John 11:11).</p>',
    "4": '<p>"...or my enemy will say, \'I have overcome him,\' and my foes will rejoice when I fall" — what Satan and the powers declared at the cross. They believed they had overcome him: "He saved others; let him save himself if he is God\'s Messiah, the Chosen One" (Luke 23:35). But 1 Cor 15:54-57: "Death is swallowed up in victory... thanks be to God! He gives us the victory through our Lord Jesus Christ." The enemy\'s premature victory cry was silenced on the third day.</p>',
    "5": '<p>"But I trust in your unfailing love; my heart rejoices in your salvation" — the pivot of trust that characterized Christ\'s entire relationship with the Father. "Father, into your hands I commit my spirit" (Luke 23:46) — the last words of Jesus from the cross, citing Ps 31:5. Even at the point of death, the trust in the Father\'s unfailing love did not fail. Heb 12:2: "For the joy set before him he endured the cross, scorning its shame" — the rejoicing in salvation that sustained Christ through death.</p>',
    "6": '<p>"I will sing the LORD\'s praise, for he has been good to me" — the vow of praise after rescue. Heb 2:12 cites Ps 22:22 ("I will declare your name to my brothers; in the assembly I will sing your praises") as the risen Christ\'s proclamation in the church. The resurrection transforms the lament of Ps 13:1-4 into the praise of v. 5-6. Christ leads the assembly\'s praise (Eph 5:19-20; Heb 2:11-12) — the firstborn who has been brought through death to eternal life now sings at the head of the congregation of the redeemed.</p>'
  },
  "14": {
    "1": '<p>"The fool says in his heart, \'There is no God.\' They are corrupt, their deeds are vile; there is no one who does good" — Paul cites this verse as part of his comprehensive indictment in Rom 3:10-12: "There is no one righteous, not even one... there is no one who does good, not even one." The diagnosis is universal — and universally applicable, pointing to the absolute need for a righteousness that comes not from human performance but from divine gift. Christ is "the righteousness of God" made available to all who believe (Rom 3:21-22; 1 Cor 1:30).</p>',
    "2": '<p>"The LORD looks down from heaven on all mankind to see if there are any who understand, any who seek God" — the divine survey that finds no one righteous. The gospel responds to this divine survey: God found what he was looking for — not in a fallen human being but in the eternal Son who became human. Christ "sought" the Father perfectly (John 8:29: "I always do what pleases him"), "understood" the divine will fully (John 5:19-20), and became the one human being who met the divine assessment. In him, those who seek God are gathered.</p>',
    "3": '<p>"All have turned away, all have become corrupt; there is no one who does good, not even one" — Paul quotes vv. 1-3 in Rom 3:10-12 to establish the universal scope of sin, making Christ\'s atoning work necessary for all. The "not even one" is absolute — there is no natural exception, no culture or era where human goodness suffices. This universality of need creates the universality of the gospel\'s offer: "for all have sinned and fall short of the glory of God, and all are justified freely by his grace through the redemption that came by Christ Jesus" (Rom 3:23-24).</p>',
    "4": '<p>"Do all these evildoers know nothing? They devour my people as though eating bread" — the persecution of God\'s people. Christ identified himself with the persecuted: "Whatever you did for one of the least of these brothers and sisters of mine, you did for me" (Matt 25:40). And more directly on the Damascus road: "Saul, Saul, why do you persecute me?" (Acts 9:4) — the risen Christ\'s identification with his persecuted body was total. To devour Christ\'s people is to devour Christ himself.</p>',
    "5": '<p>"But there they are, overwhelmed with dread, for God is present in the company of the righteous" — the sudden reversal: the persecutors are overwhelmed when they discover that God himself is present with those they are attacking. This is the great reversal of the cross and resurrection: those who crucified Jesus thought they were eliminating a threat; they discovered (Acts 2:36: "God has made this Jesus, whom you crucified, both Lord and Messiah") that they had attacked the one in whom God was fully present (Col 2:9: "in Christ all the fullness of the Deity lives in bodily form").</p>',
    "6": '<p>"You evildoers frustrate the plans of the poor, but the LORD is their refuge" — Christ as refuge for the poor, whose plans are consistently frustrated by the powerful. Luke 1:52-53 (the Magnificat): "He has brought down rulers from their thrones but has lifted up the humble. He has filled the hungry with good things but has sent the rich away empty." Christ reversed the social order of frustration: the poor whose plans are frustrated by the powerful are the ones whose prayers he hears and whose cause he champions.</p>',
    "7": '<p>"Oh, that salvation for Israel would come out of Zion! When the LORD restores his people, let Jacob rejoice and Israel be glad!" — the eschatological cry answered in Christ. Rom 11:26: "And in this way all Israel will be saved. As it is written: \'The deliverer will come from Zion; he will turn godlessness away from Jacob.\'" Christ came from Zion (in the sense of the covenant people) and will return to restore fully. The prayer of Ps 14:7 is the Advent prayer — oh, that the salvation would come — answered by "it is finished" (John 19:30) and awaiting its completion at the second coming.</p>'
  },
  "15": {
    "1": '<p>"LORD, who may dwell on your holy mountain?" — the entrance liturgy\'s question, which Christ alone answers from his own nature and which his people answer through union with him. Heb 12:22-24: "You have come to Mount Zion, to the city of the living God, the heavenly Jerusalem... to Jesus the mediator of a new covenant." Access to the holy mountain is through Christ the mediator. He is simultaneously the answer to the question (he alone qualifies perfectly) and the one through whom others are qualified.</p>',
    "2": '<p>"The one whose walk is blameless, who does what is righteous, who speaks the truth from their heart" — the three qualifications Christ alone perfectly met. "Blameless (<em>tāmîm</em>)" — Christ was without sin (Heb 4:15; 2 Cor 5:21). "Does what is righteous" — "the Righteous One" is a Messianic title (Acts 3:14; 7:52; 22:14). "Speaks the truth from their heart" — Christ is "the truth" in his very person (John 14:6), the one in whom word and heart are perfectly aligned. These qualities describe the covenant-keeper par excellence.</p>',
    "3": '<p>"...whose tongue utters no slander, who does no evil to a neighbor, and casts no slur on others" — Christ perfectly fulfilled each of these. He spoke no slander. He did no evil to any neighbor — even his trial and crucifixion were initiated and carried out by others. 1 Pet 2:22-23: "He committed no sin, and no deceit was found in his mouth. When they hurled their insults at him, he did not retaliate; when he suffered, he made no threats." The standard of Ps 15:3 is met only in the one who bore insult without returning it.</p>',
    "4": '<p>"...who despises a vile person but honors those who fear the LORD; who keeps an oath even when it hurts, and does not change their mind" — Christ kept his covenant oath at infinite personal cost. "Having loved his own who were in the world, he loved them to the end" (John 13:1). The garden prayer "if it is possible, may this cup be taken from me" was the voice of the cost; "yet not as I will, but as you will" (Matt 26:39) was the oath kept regardless. He "endured the cross, scorning its shame" (Heb 12:2) — the ultimate oath-keeping at infinite cost.</p>',
    "5": '<p>"...who lends money to the poor without interest; who does not accept a bribe against the innocent. Whoever does these things will never be shaken" — Christ, who could not be bribed (the thirty pieces of silver were paid to Judas to betray him, not to him to betray others), who charged no one for healing, who gave freely to all who came — embodies the economic justice described here. "Never be shaken (<em>lōʾ yimmôṭ</em>)" — the promise of unshakeable security for those who dwell on the holy mountain through Christ (Heb 12:27-28: we are "receiving a kingdom that cannot be shaken").</p>'
  },
  "16": {
    "1": '<p>"Keep me safe, my God, for in you I take refuge" — the prayer of the incarnate Son to the Father. John 17 is the extended version of this prayer: "Holy Father, protect them by the power of your name... My prayer is not that you take them out of the world but that you protect them from the evil one" (John 17:11, 15). Christ both prayed this prayer himself (for himself in Gethsemane, for his disciples in John 17) and answers it for those who take refuge in him.</p>',
    "2": '<p>"I say to the LORD, \'You are my Lord; apart from you I have no good thing\'" — Christ\'s absolute dependence on the Father. John 5:19: "the Son can do nothing by himself; he can do only what he sees his Father doing." John 5:30: "I can do nothing by myself." The incarnate Son expressed the created dependence of humanity in its perfected form — not a forced dependence but a freely chosen one, grounded in the love between Father and Son. This verse describes what Adam failed to live and what Christ perfectly embodied.</p>',
    "3": '<p>"I say of the holy people who are in the land: \'They are the noble ones in whom is all my delight\'" — Christ\'s love for his church. John 15:9: "As the Father has loved me, so have I loved you." Eph 5:25-27: Christ loved the church and gave himself up for her "to present her to himself as a radiant church, without stain or wrinkle or any other blemish, but holy and blameless." His delight in the saints ("noble ones") is the Father\'s delight in the Son extended to all who are united to him (John 17:26: "the love you have for me may be in them").</p>',
    "4": '<p>"Those who run after other gods will suffer more and more. I will not pour out libations of blood to such gods or take up their names on my lips" — Christ\'s absolute rejection of every competing loyalty. "You shall have no other gods before me" was the first commandment that every Israelite failed; Christ alone lived it perfectly. His temptation (Matt 4:1-11) was specifically the temptation to worship another (Satan\'s offer of the kingdoms of the world) and he refused. His entire life was the enacted form of this verse.</p>',
    "5": '<p>"LORD, you are my portion and my cup; you have made my lot secure" — Christ\'s contentment in the Father alone. The "portion" language recalls the Levitical priesthood (Num 18:20 — "the LORD himself is their inheritance" for the Levites who received no land portion). Christ, as the great High Priest, received the Father as his inheritance rather than earthly kingdoms (Matt 4:8-10 — he refused the kingdoms offered by Satan). For believers united to Christ, the Father himself becomes the inheritance: "If you are Christ\'s, then you are Abraham\'s seed, and heirs according to the promise" (Gal 3:29).</p>',
    "6": '<p>"The boundary lines have fallen for me in pleasant places; surely I have a delightful inheritance" — the perfect contentment of Christ in the Father\'s provision. This contrasts with Adam\'s refusal of contentment (Gen 3 — he grasped at what God had not yet given) and the devil\'s temptation in Matt 4 (offering what the Father had not yet assigned). Christ\'s "delightful inheritance" is ultimately the resurrection: "You are my Son; today I have become your Father. Ask me, and I will make the nations your inheritance" (Ps 2:7-8).</p>',
    "7": '<p>"I will praise the LORD, who counsels me; even at night my heart instructs me" — Christ\'s communion with the Father through prayer. Jesus regularly prayed through the night (Luke 6:12) and rose before dawn to pray (Mark 1:35). The "instruction of the heart at night" describes the intimacy of the Father-Son relationship in prayer — a communion that sustained Christ\'s human nature through its suffering and that he invites his disciples to share ("when you pray, go into your room, close the door and pray to your Father" — Matt 6:6).</p>',
    "8": '<p>"I keep my eyes always on the LORD. With him at my right hand, I will not be shaken" — Peter cites this verse in Acts 2:25-28 explicitly as David speaking of Christ. "He was not shaken" — tested at every point, Christ\'s orientation toward the Father never wavered (Heb 12:2: "For the joy set before him he endured the cross, scorning its shame, and sat down at the right hand of the throne of God"). The unshakeable fixity of Christ on the Father is the pattern for the believer: "fixing our eyes on Jesus, the pioneer and perfecter of faith" (Heb 12:2).</p>',
    "9": '<p>"Therefore my heart is glad and my tongue rejoices; my body also will rest secure" — Peter quotes this verse in Acts 2:26 as prophetic of Christ\'s resurrection. The "resting secure" of the body is the assurance against bodily corruption in the grave — the body of Christ would not remain in death. Luke 24:41 records the risen Christ\'s joy: "while they still did not believe it because of joy and amazement..." The gladness of this verse is specifically the gladness of the resurrection — the body secured against the grave.</p>',
    "10": '<p>"...because you will not abandon me to the realm of the dead, nor will you let your faithful one see decay" — the key resurrection prophecy in this psalm range. Peter cites it directly in Acts 2:27, 31: "he seeing this before spoke of the resurrection of the Christ, that his soul was not left in Hades, neither did his flesh see corruption." Paul quotes it in Acts 13:35-37: "as David\'s body decayed, \'but the one whom God raised from the dead did not see decay.\'" This is the central Christological verse of Ps 16: the promise that the "faithful one" (<em>ḥāsîd</em>) — the covenantal loyal one — would not see decay is uniquely fulfilled in Jesus.</p>',
    "11": '<p>"You make known to me the path of life; you will fill me with joy in your presence, with eternal pleasures at your right hand" — the resurrection and ascension. "The path of life" — Christ is "the resurrection and the life" (John 11:25), "the way and the truth and the life" (John 14:6). "Joy in your presence" — the joy of the Father\'s welcome at the ascension (John 17:5: "Father, glorify me in your presence with the glory I had with you before the world began"). "Eternal pleasures at your right hand" — the heavenly session (Ps 110:1; Heb 1:3; Rev 3:21). This verse is the end of the path that began at the cross.</p>'
  },
  "17": {
    "1": '<p>"Hear me, LORD, my plea is just (<em>ṣeḏeq</em>); listen to my cry. Hear my prayer — it does not rise from deceitful lips" — Christ as the only human being whose plea before God is perfectly just and completely without deceit. All human prayers are mixed with self-interest and incomplete honesty; Christ\'s prayer in John 17 ("I have brought you glory on earth by finishing the work you gave me to do") is the only perfectly just petition. He is simultaneously the one who prays righteously (this verse) and the one whose intercession makes our imperfect prayers acceptable (Heb 7:25; Rom 8:34).</p>',
    "2": '<p>"Let my vindication come from you; may your eyes see what is right" — the prayer for divine vindication answered in the resurrection. The resurrection was the Father\'s verdict on the son\'s claim: the cross appeared to be defeat and judgment; the empty tomb declared him righteous. Rom 4:25: Christ "was delivered over to death for our sins and was raised to life for our justification." The vindication ("justification") of Christ is the ground of the justification of all who are in him.</p>',
    "3": '<p>"Though you probe my heart and examine me at night; though you test me, you will find that I have done nothing wrong; I have resolved that my mouth will not sin" — the examination that only Christ passed without finding sin. Heb 4:15: "we have one who has been tempted in every way, just as we are — yet he did not sin." 1 Pet 2:22: "He committed no sin, and no deceit was found in his mouth." The divine probing and testing of Christ found nothing — the verdict of perfect innocence that became the basis for the imputation of righteousness to all who believe (2 Cor 5:21).</p>',
    "4": '<p>"As for what others do — following your word I have kept myself from the ways of the violent" — Christ\'s separation from the patterns of the world. Though accused of being "a friend of tax collectors and sinners" (Matt 11:19), Jesus remained without sin — he entered the company of the violent and corrupt not to participate but to rescue (Luke 19:10: "the Son of Man came to seek and to save the lost"). His presence among sinners was not contamination but rescue — "he did not consider equality with God something to be used to his own advantage... he humbled himself" (Phil 2:6-8) while remaining without sin.</p>',
    "5": '<p>"My steps have held to your paths; my feet have not stumbled" — the perfect walk of Christ. Every other human being has stumbled from the path (Ps 14:3: "they have all turned away"); Christ alone walked the entire way without stumbling (Heb 12:2: "he endured the cross, scorning its shame"). The "path" language connects to Ps 16:11 ("you make known to me the path of life") — the path of perfect obedience that Christ walked from Bethlehem to Calvary to the empty tomb, and which his people are enabled to walk in him (Col 2:6: "walk in him").</p>',
    "6": '<p>"I call on you, my God, for you will answer me; turn your ear to me and hear my prayer" — the confidence in answered prayer that characterized Christ\'s relationship with the Father. John 11:42: "I knew that you always hear me." John 17:1: "Father, the hour has come. Glorify your Son, that your Son may glorify you." Christ prayed with the certainty of being heard — a certainty grounded in the unbroken communion of the eternal Father-Son relationship maintained through the incarnation. This confidence is extended to believers: "if we ask anything according to his will, he hears us" (1 John 5:14).</p>',
    "7": '<p>"Show me the wonders of your great love, you who save by your right hand those who take refuge in you from their foes" — the wonders of divine love reached their apex in the incarnation and crucifixion. John 3:16: "For God so loved the world that he gave his one and only Son." 1 John 4:9-10: "This is how God showed his love among us: He sent his one and only Son into the world... not that we loved God, but that he loved us and sent his Son as an atoning sacrifice for our sins." The "wonders of great love" (<em>ḥasdêkā</em>) are the covenant loyalties made visible in Christ.</p>',
    "8": '<p>"Keep me as the apple of your eye; hide me in the shadow of your wings" — Christ\'s intercession for his people. John 17:11: "Holy Father, protect them by the power of your name, those you have given me." John 17:15: "My prayer is not that you take them out of the world but that you protect them from the evil one." Christ prays the exact prayer of this verse on behalf of all believers — that they be kept as precious and sheltered as the apple of the divine eye. The prayer of the psalmist becomes Christ\'s prayer for the church.</p>',
    "9": '<p>"...from the wicked who are out to destroy me, from my mortal enemies who surround me" — the reality of deadly opposition that Christ faced. He was "surrounded" at the end: betrayed within his own circle, tried before the Sanhedrin, handed to Pilate, crucified between criminals, mocked by passersby. The "mortal enemies" were both human (the chief priests, the Roman soldiers) and cosmic (the powers and principalities — Col 2:15). Christ did not evade the surrounding — he allowed it to complete, trusting the Father to vindicate him.</p>',
    "10": '<p>"They close up their callous hearts, and their mouths speak with arrogance" — the hardness of heart that opposed and crucified Christ. John 12:40 (citing Isa 6:10): "He has blinded their eyes and hardened their hearts, so they can neither see with their eyes, nor understand with their hearts." The arrogance of the religious leaders who condemned Jesus ("if this man were a prophet, he would know..." Luke 7:39; "we have no king but Caesar" John 19:15) fulfilled this description completely.</p>',
    "11": '<p>"They have tracked down my steps, surrounding me; with eyes alert, to throw me to the ground" — the hunting of Christ in the Passion. John 18:3-8 describes the scene: Judas arriving with soldiers and officials carrying torches and weapons, surrounding Jesus in Gethsemane. Jesus stepped forward and said "I am he" — and they fell to the ground. The very "throwing to the ground" that the enemies intended for him happened to them at the sound of his divine self-identification. Even in his arrest, Christ demonstrated sovereign authority.</p>',
    "12": '<p>"They are like a lion hungry for prey, like a fierce lion crouching in cover" — the lion imagery connects to 1 Pet 5:8 (Satan as a roaring lion) and Rev 5:5 (Christ as the Lion of Judah). The enemy crouches like a lion to attack the psalmist — ultimately, to attack Christ. But the attack on Christ became the instrument of the enemy\'s defeat: "having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross" (Col 2:15). The lion that crouched to devour was disarmed by the willing sacrifice of the Lamb.</p>',
    "13": '<p>"Rise up, LORD, confront them, bring them down; with your sword rescue me from the wicked" — the prayer for divine intervention answered definitively in the resurrection and the final judgment. The risen Christ declares "I hold the keys of death and Hades" (Rev 1:18) — the sword of judgment is now his. The final bringing-down of all who oppose Christ awaits the return: "The Lord Jesus will overthrow [the lawless one] with the breath of his mouth and destroy by the splendor of his coming" (2 Thess 2:8). The prayer of the cross ("Father, into your hands I commit my spirit") is also a prayer for this confrontation.</p>',
    "14": '<p>"By your hand save me from such people, LORD, from those whose reward is in this life" — Christ\'s perspective on earthly reward. He consistently refused the earthly kingdom (John 6:15: "Jesus, knowing that they intended to come and make him king by force, withdrew again to a mountain by himself"). The temptation to pursue the kingdoms of the world (Matt 4:8-10) was the temptation to "have his reward in this life." Christ\'s reward was deferred: "For the joy set before him he endured the cross" (Heb 12:2) — the reward was resurrection-life, not earthly power.</p>',
    "15": '<p>"As for me, I will see your face in righteousness; when I awake, I will be satisfied with seeing your likeness" — the culminating resurrection verse of this psalm range. "When I awake" (<em>bĕhāqîṣ</em>) is the "awaking" from death that the OT uses as a resurrection metaphor (Job 14:12; Isa 26:19; Dan 12:2). This verse describes what Christ experienced at the resurrection: he "awoke" to see the Father\'s face in the righteousness he had maintained through death. For believers, this is the promise of final glory: 1 John 3:2 ("when Christ appears, we shall be like him, for we shall see him as he is") and Rev 22:4 ("they will see his face").</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-christ', 'psalms', existing)
    print('Psalms 9-17 mkt-christ written.')

if __name__ == '__main__':
    main()
